def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[1]  # slide 2 (0-based)

    icons_found = 0
    for shape in slide.shapes:
        if shape.shape_type == 13 or hasattr(shape, 'image'):  # picture, icon, auto shape
            icons_found += 1

    if icons_found == 3:
        return "Icons/symbols found inside each of the three circles.", 1.0
    elif icons_found == 2:
        return "Icons/symbols found in only 2 circles.", 2/3
    elif icons_found == 1:
        return "Icon/symbol found in only 1 circle.", 1/3
    else:
        return "No icons/symbols found inside circles.", 0.0

def compute_score() -> tuple[str, float]:
    added_slides = ppt_diff.added_slides
    if len(added_slides) > 0:
        return f"Expected 0 slide added, found {len(added_slides)}.", 0.0

    if len(ppt_diff.removed_slides) != 0:
        return f"{len(ppt_diff.removed_slides)} slides removed, expected 0.", 0.0
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        return "Animations were changed, which is extraneous.", 0.0
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        return "Transitions were changed, which is extraneous.", 0.0

    return ('No differences found', 1.0)
